export const ListAlertsResponse = {
  /**
   * Serializes ListAlertsResponse to protobuf.
   */
  encode: function (msg: PartialDeep<ListAlertsResponse>): Uint8Array {
    return ListAlertsResponse._writeMessage(
      msg,
      new protoscript.BinaryWriter(),
    ).getResultBuffer();
  },

  /**
   * Deserializes ListAlertsResponse from protobuf.
   */
  decode: function (bytes: ByteSource): ListAlertsResponse {
    return ListAlertsResponse._readMessage(
      ListAlertsResponse.initialize(),
      new protoscript.BinaryReader(bytes),
    );
  },

  /**
   * Initializes ListAlertsResponse with all fields set to their default value.
   */
  initialize: function (msg?: Partial<ListAlertsResponse>): ListAlertsResponse {
    return {
      status: common.ResponseStatus.initialize(),
      alerts: [],
      totalCount: 0n,
      limit: 0,
      offset: 0,
      ...msg,
    };
  },

  /**
   * @private
   */
  _writeMessage: function (
    msg: PartialDeep<ListAlertsResponse>,
    writer: protoscript.BinaryWriter,
  ): protoscript.BinaryWriter {
    if (msg.status) {
      writer.writeMessage(1, msg.status, common.ResponseStatus._writeMessage);
    }
    if (msg.alerts?.length) {
      writer.writeRepeatedMessage(2, msg.alerts as any, Alert._writeMessage);
    }
    if (msg.totalCount) {
      writer.writeInt64String(3, msg.totalCount.toString() as any);
    }
    if (msg.limit) {
      writer.writeInt32(4, msg.limit);
    }
    if (msg.offset) {
      writer.writeInt32(5, msg.offset);
    }
    return writer;
  },

  /**
   * @private
   */
  _readMessage: function (
    msg: ListAlertsResponse,
    reader: protoscript.BinaryReader,
  ): ListAlertsResponse {
    while (reader.nextField()) {
      const field = reader.getFieldNumber();
      switch (field) {
        case 1: {
          reader.readMessage(msg.status, common.ResponseStatus._readMessage);
          break;
        }
        case 2: {
          const m = Alert.initialize();
          reader.readMessage(m, Alert._readMessage);
          msg.alerts.push(m);
          break;
        }
        case 3: {
          msg.totalCount = BigInt(reader.readInt64String());
          break;
        }
        case 4: {
          msg.limit = reader.readInt32();
          break;
        }
        case 5: {
          msg.offset = reader.readInt32();
          break;
        }
        default: {
          reader.skipField();
          break;
        }
      }
    }
    return msg;
  },
};

